+codeunit 30366 "Shpfy Copy Document Mgt."
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesDocument', '', false, false)]
+    local procedure ClearShopifyFieldsOnAfterCopySalesDocument(var ToSalesHeader: Record "Sales Header")
+    begin
+        ClearShopifyFields(ToSalesHeader);
+    end;
+
+    local procedure ClearShopifyFields(var SalesHeader: Record "Sales Header")
